import{drop}from"@hyperjump/pact";import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{getKeywordName,Validation}from"../experimental.js";const id="https://json-schema.org/keyword/items",compile=async(e,t,r)=>{var o=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/prefixItems"),o=await Browser.step(o,r);return["array"===Browser.typeOf(o)?Browser.length(o):0,await Validation.compile(e,t)]},interpret=([e,t],r,o,a,n)=>{if("array"!==Instance.typeOf(r))return!0;let i=!0;for(const s of drop(e,Instance.iter(r)))Validation.interpret(t,s,o,a,n)||(i=!1);return i},collectEvaluatedItems=(t,r,e,o)=>{if(!interpret(t,r,e,o,!0))return!1;const a=new Set;for(let e=t[0];e<Instance.length(r);e++)a.add(e);return a};export default{id:id,compile:compile,interpret:interpret,collectEvaluatedItems:collectEvaluatedItems};